module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const dir = (args.direction || 'row').toLowerCase() === 'column' ? 'column' : 'row';
const shape = (args.shape || 'square').toLowerCase();
const size = { small: '11px', medium: '15px', large: '20px' }[String(args.size || 'medium').toLowerCase()] || '15px';
const gap = (args.gap && String(args.gap).trim()) || '8px 18px';
const weight = String(args.bold) === 'true' ? '700' : '400';
const items = [];
sections.forEach((s) => {
  const m = String(s || '').trim().match(/^([\s\S]*?)[:|]\s*([\s\S]+)$/);
  if (!m) return;
  items.push({ color: m[1].trim(), label: m[2].trim() });
});
let html = `\n\n<div class="mdp-mod-legend mdp-lg-${dir}" style="--lg-size:${size}; --lg-weight:${weight}; gap:${gap};">`;
items.forEach((it) => {
  html += `<div class="mdp-lg-item"><span class="mdp-lg-swatch mdp-lg-${shape}" style="--lg-c:${esc(it.color)};"></span><span class="mdp-lg-label">${esc(it.label)}</span></div>`;
});
html += `</div>\n\n`;
return html;
